body.script:
        const routines = [
            [
                { name: "Press Mancuernas (Pecho)", base: "45 lb x 8 reps" },
                { name: "Remo con Barra (Espalda)", base: "40 lb x 10 reps" },
                { name: "Press Militar (Hombro)", base: "20 lb x 10 reps" },
                { name: "Dominadas (Espalda)", base: "6 reps (Al fallo)" }
            ],
            [
                { name: "Sentadilla Libre (Pierna)", base: "45 lb x 10 reps" },
                { name: "Peso Muerto Rumano", base: "50 lb x 10 reps" },
                { name: "Prensa Inclinada", base: "90 lb x 12 reps" },
                { name: "Abdomen Banco Inclinado", base: "20 reps" }
            ],
            [
                { name: "Press Inclinado Mancuernas", base: "40 lb x 12 reps" },
                { name: "Jalón al Pecho Polea", base: "35 lb x 12 reps" },
                { name: "Elevaciones Laterales (Hombro)", base: "15 lb x 12 reps" },
                { name: "Curl Barra (Bíceps)", base: "30 lb x 12 reps" }
            ],
            [
                { name: "Sentadilla Goblet", base: "30 lb x 12 reps" },
                { name: "Desplantes con Mancuerna", base: "20 lb x 10 reps" },
                { name: "Tríceps Polea Alta", base: "30 lb x 12 reps" },
                { name: "Toes to Bar (Abdomen)", base: "7 reps" }
            ],
            [
                { name: "Sentadilla Libre", base: "40 lb x 12 reps" },
                { name: "Press de Pecho Plano", base: "40 lb x 12 reps" },
                { name: "Dominadas", base: "6 reps" },
                { name: "Elevación Frontal Hombro", base: "15 lb x 10 reps" }
            ]
        ];

        let totalCals = 0;
        let totalProt = 0;
        let pendingCals = 0;
        let pendingProt = 0;

        const mealsPool = [
            { text: "Licuado Pro-Volumen: Avena, leche entera, crema de cacahuate y plátano", cals: 850, prot: 35 },
            { text: "Almuerzo de Campeones: 200g de Pechuga de pollo, 1.5 tazas de arroz y 1/2 aguacate", cals: 900, prot: 50 },
            { text: "Cena de Recuperación: Carne de res magra, papas al horno con mantequilla y ensalada", cals: 850, prot: 45 }
        ];
        let mealIndex = 0;

        function switchTab(tabId, btn) {
            document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));
            document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
            document.getElementById(tabId).classList.add('active');
            btn.classList.add('active');
        }

        function loadRoutine() {
            const dayIdx = document.getElementById('daySelect').value;
            const container = document.getElementById('routineExercises');
            container.innerHTML = '';

            routines[dayIdx].forEach((ex, idx) => {
                container.innerHTML += `


                        ${ex.name}

Objetivo sugerido: ${ex.base}





                        Guardar Serie

                `;
            });
        }

        function saveSet(name, dIdx, eIdx) {
            const w = document.getElementById(`w_${dIdx}_${eIdx}`).value;
            const r = document.getElementById(`r_${dIdx}_${eIdx}`).value;
            if(!w || !r) return alert("Por favor ingresa peso y repeticiones");
            alert(`¡Serie guardada para ${name}! Volumen movido: ${w * r} lbs. ¡Sigue así para la carga progresiva!`);
        }

        function simulatePhotoScan() {
            const currentMeal = mealsPool[mealIndex % mealsPool.length];
            pendingCals = currentMeal.cals;
            pendingProt = currentMeal.prot;

            document.getElementById('foodAnalysis').innerHTML = `Detectado: ${currentMeal.text}
Estimación: ~${currentMeal.cals} kcal | ${currentMeal.prot}g Proteína`;
            document.getElementById('photoArea').style.display = 'block';
            mealIndex++;
        }

        function confirmMeal() {
            totalCals += pendingCals;
            totalProt += pendingProt;

            document.getElementById('currentCals').innerText = totalCals;
            document.getElementById('currentProt').innerText = totalProt;

            let pct = (totalCals / 2600) * 100;
            document.getElementById('calBar').style.width = `${Math.min(pct, 100)}%`;

            document.getElementById('photoArea').style.display = 'none';
            alert("¡Calorías añadidas a tu registro diario!");
        }

        // Carga inicial
        loadRoutine();
